INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-00281', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '孩子：你別管我好嗎？我知道我要怎麼做，不需要你每一秒鐘提醒我。家長：我需要不斷提醒你， 否則你根本不會去做，如果你能讓我信任你，我也不用一直盯著你。上述情形最能反映家長與青 少年孩子關係的何種發展主題？', '["威權與控制", "放任與控制", "溺愛與控制", "自主與控制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00282', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '發展樂觀正向和幸福感，是幫助人們因應生活改變和挑戰的可行策略。而Seligman提到創造幸福 感，必須包括那三個基本的改變？', '["對過去個人生活感到更幸福、對現在的親密關係感到更幸福、對家庭的未來感到更幸福", "對自己的過去感到更幸福、對自己現在的生活感到更幸福、對自己的未來感到更幸福", "對自己的過去感到更幸福、對現在的社會生活感到更幸福、對國家的未來感到更幸福", "對過去家庭生活感到更幸福、對現在的家庭生活感到更幸福、對未來的家庭生活感到更幸福"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00283', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者對繼親家庭提供服務時，可採取的因應策略有那些？①財務和居住安排  ②解決前段', '["覺察孩子的需求", "考慮孩子的性別和差異  ⑤避免與無監護權的家長維持積 極的正向關係", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00284', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年自殺比例逐年攀升，值得令人重視，儘管影響自殺的因素相當複雜，但關鍵因素包括有那', '["遭受肢體或性虐待", "生活壓力（如學業）", "性傾向遭受歧視", "家長過度保護"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00285', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '某甲八歲，是地震的受災者，之後每天到學校上課時，都會隨身攜帶一頂機車安全帽，只要有任 何晃動，不論大小，他都會馬上戴上安全帽，持續性哭泣。有關某甲行為的合理解釋，符合下列 何者？', '["創傷後壓力症候群", "自我懷疑", "萬物有靈論", "罪惡感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00286', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者在協助親密暴力的受暴孕婦，需要注意的技巧，下列敘述何者正確？①評估的時候要', '["訪談的時候，應該將女性與配 偶隔開，分開訪談", "受暴女性對女性社會工作者，比較容易吐露受暴問題，社會工作者的性別 選擇很重要，訪談技巧比較不重要", "使用沒有壓迫感的開放性問句幫助非自願案主吐露自己的 遭遇，例如「我看到你身上的傷，他是不是對你施暴？」", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00287', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「出櫃」對青少年同志是十分困難的決定，Sauerman（2004）為此編著指引手冊，下列敘述何者 錯誤？', '["要準備好面對家長聽到出櫃時，可能會出現的沮喪反應", "趁著與家長發生爭執時出櫃，才能一次把話說清楚", "出櫃後，需要給家長時間和空間好好消化這個訊息", "準備相關資料與提供同志家長專線，讓他們可求助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00288', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '尊重多元性別是性別平等教育的重要原則，然而面對跨性別兒童的性別重建仍有許多爭議，請問 下列那項做法違反社會工作倫理？', '["建議有雙性特徵新生兒的家長，應等待孩子能表達自己的性別認同再決定", "協助家有跨性別兒童的家長了解此性別認同不代表罹患精神疾病", "建議生下隱睪症新生兒的家長在孩子尚未發育前接受性別重建手術", "提供想接受性別重建手術之兒童與家長具實證基礎的資訊，以做出最好決定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00289', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '提供「跨族群領養」服務時，對社會工作者評估能力與處遇計畫的敘述，下列何者錯誤？', '["對想領養不同族群兒童的家長，評估其熟悉跨族群議題的文化能力", "為提升孩子被領養後的族群認同，應避免他們接觸原本所屬之族群與文化", "營造安全氣氛，協助原生家長孩子的分離，並規劃未來與小孩的接觸計畫", "處理原住民兒童領養時，應將原生家庭與部落的意見同時納入評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00290', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者對新住民兒童提供以「民族意識優勢」的處遇服務時，下列敘述何者最不適當？', '["與家長討論並了解其家長原生文化的優勢，協助他們決定想傳承的傳統文化內容", "協助學校老師與家長創造能突顯原生文化優勢的活動，提升孩子對此文化的興趣", "助人者應保持文化敏感度與自我覺察，以利與新住民溝通時有更好的交流與認同", "增強家長與新住民兒童對臺灣的族群認同，以避免原生文化對兒童發展造成干擾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
